import React from 'react'
import tick from "../images/greenTick.png"

const PaymentSuccess = () => {

    let urlElements = window.location.href.split('=')

  return (
    <div className='flex flex-col justify-center items-center text-white gap-2'>
        <img src={tick} width={210}></img>
        <h2 className='uppercase font-nunito text-3xl font-bold tracking-wide'>Order Successfull</h2>
        <p className='font-nunito text-xl font-semibold tracking-wide mb-10'>Reference No.{urlElements[1]}</p>
        
    </div>
  )
}

export default PaymentSuccess
